"use client";

import React, { useState } from "react";
import { useRouter } from "next/navigation";
import { Package, MapPin, Settings, LogOut, ArrowLeft, Heart, Check, X, Camera } from "lucide-react";
import { useAuth } from "@/lib/AuthProvider";
import { MenuButton } from "@/components/ui/profile-menu-button";

export default function ProfilePage() {
  const { user, logout, updateUser } = useAuth(); // Certifique-se que seu useAuth tem updateUser
  const router = useRouter();

  // Estados para edição
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    name: user?.name || "",
    email: user?.email || "",
  });

  if (!user) return null;

  const handleSave = () => {
    if (updateUser) {
      updateUser(formData); // Atualiza no Contexto/Storage
      setIsEditing(false);
      alert("Perfil atualizado com sucesso!");
    } else {
      // Caso não tenha a função no contexto ainda, salvamos direto
      const updatedUser = { ...user, ...formData };
      localStorage.setItem("nani_user", JSON.stringify(updatedUser));
      setIsEditing(false);
      window.location.reload(); // Recarrega para aplicar
    }
  };

  return (
    <div className="min-h-screen bg-[#FDFBF9] font-sans text-black">
      {/* Header */}
      <div className="bg-white border-b border-gray-100 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center justify-between">
          <button onClick={() => router.back()} className="p-2 hover:bg-gray-50 rounded-full transition-colors">
            <ArrowLeft size={20} className="text-gray-600" />
          </button>
          <h1 className="text-sm font-black uppercase tracking-[0.3em] text-gray-400">Meu Perfil</h1>
          <button onClick={() => { logout(); router.push("/"); }} className="p-2 text-red-400 hover:bg-red-50 rounded-full transition-colors">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      <main className="max-w-4xl mx-auto px-6 py-10">
        {/* Identidade / Card de Perfil */}
        <div className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-50 flex flex-col md:flex-row items-center gap-8 mb-10 transition-all">
          
          {/* Avatar com ícone de câmera se estiver editando */}
          <div className="relative">
            <div className="w-28 h-28 bg-[#9C7C50] rounded-full flex items-center justify-center text-white text-4xl font-black shadow-xl ring-4 ring-[#9C7C50]/10">
              {formData.name.charAt(0).toUpperCase()}
            </div>
            {isEditing && (
              <div className="absolute bottom-0 right-0 p-2 bg-black text-white rounded-full border-2 border-white cursor-pointer">
                <Camera size={14} />
              </div>
            )}
          </div>

          <div className="text-center md:text-left flex-1 space-y-2">
            {isEditing ? (
              <div className="space-y-3">
                <input 
                  type="text" 
                  className="w-full md:w-auto bg-gray-50 border border-gray-200 rounded-xl px-4 py-2 font-bold outline-none focus:ring-2 focus:ring-[#9C7C50]/20"
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  placeholder="Seu nome"
                />
                <input 
                  type="email" 
                  className="w-full md:w-auto block bg-gray-50 border border-gray-200 rounded-xl px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-[#9C7C50]/20"
                  value={formData.email}
                  onChange={(e) => setFormData({...formData, email: e.target.value})}
                  placeholder="Seu email"
                />
              </div>
            ) : (
              <>
                <h2 className="text-3xl font-black text-gray-900 tracking-tight">{user.name}</h2>
                <p className="text-gray-400 font-medium tracking-wide">{user.email}</p>
              </>
            )}
          </div>

          {/* Botões de Ação */}
          <div className="flex gap-2">
            {isEditing ? (
              <>
                <button 
                  onClick={() => setIsEditing(false)}
                  className="p-4 bg-gray-100 text-gray-400 rounded-2xl hover:bg-gray-200 transition-all"
                >
                  <X size={20} />
                </button>
                <button 
                  onClick={handleSave}
                  className="bg-[#9C7C50] text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-[#9C7C50]/20 flex items-center gap-2"
                >
                  <Check size={16} /> Salvar
                </button>
              </>
            ) : (
              <button 
                onClick={() => setIsEditing(true)}
                className="bg-black text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-[#9C7C50] transition-all shadow-xl shadow-black/10"
              >
                Editar Perfil
              </button>
            )}
          </div>
        </div>

        {/* Menu de Navegação e Outros cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-4">
            <h3 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400 ml-4 mb-6">Minha Conta</h3>
            <MenuButton 
              icon={<Package size={18} />} 
              label="Meus Pedidos" 
              onClick={() => router.push("/profile/orders")} 
            />
            <MenuButton 
              icon={<Heart size={18} />} 
              label="Lista de Desejos" 
              onClick={() => router.push("/profile/wishlist")} 
            />
            <MenuButton 
              icon={<MapPin size={18} />} 
              label="Endereços de Entrega" 
              onClick={() => router.push("/profile/addresses")} 
            />
            <MenuButton 
              icon={<Settings size={18} />} 
              label="Privacidade & Segurança" 
              onClick={() => router.push("/profile/settings")} 
            />
          </div>
          
          {/* Card de Informação Extra (Podes usar para o programa de pontos/fidelidade) */}
          <div className="bg-[#9C7C50] rounded-[32px] p-8 text-white shadow-2xl shadow-[#9C7C50]/20 relative overflow-hidden group">
            <div className="relative z-10">
              <h3 className="text-[10px] font-black uppercase tracking-widest text-white/60 mb-2">Nani Club</h3>
              <p className="text-2xl font-black mb-4">Você tem 450 pontos</p>
              <p className="text-xs text-white/80 leading-relaxed mb-6">Troque seus pontos por descontos em novos séruns e fragrâncias.</p>
              <button className="bg-white text-[#9C7C50] px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:scale-105 transition-all">
                Resgatar Agora
              </button>
            </div>
            <div className="absolute -right-4 -bottom-4 opacity-10 group-hover:rotate-12 transition-transform duration-700">
               <Package size={140} />
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}